class Stack:
    def __init__(self):
        self._data = []
    def push(self, val):
        self._data.append(val)
    def pop(self):
        if self.isEmpty():
            raise IndexError('pop from empty stack')
        return self._data.pop()
    def peek(self):
        if self.isEmpty():
            raise IndexError('peek from empty stack')
        return self._data[-1]
    def isEmpty(self):
        return len(self._data) == 0

import heapq

class MaxHeap:
    def __init__(self):
        self._data = []
    def push(self, val):
        heapq.heappush(self._data, -val)
    def pop(self):
        return -heapq.heappop(self._data)
    def peek(self):
        return -self._data[0]

def binary_search(nums, target):
    left, right = 0, len(nums) - 1
    while left <= right:
        mid = left + (right - left) // 2
        if nums[mid] == target:
            return mid
        elif nums[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

def knapsack(weights, values, capacity):
    n = len(weights)
    dp = [0] * (capacity + 1)
    for i in range(n):
        for w in range(capacity, weights[i] - 1, -1):
            dp[w] = max(dp[w], dp[w - weights[i]] + values[i])
    return dp[capacity]

def permutations(n):
    result = []
    def backtrack(path, used):
        if len(path) == n:
            result.append(path[:])
            return
        for i in range(1, n + 1):
            if used[i]:
                continue
            used[i] = True
            path.append(i)
            backtrack(path, used)
            path.pop()
            used[i] = False
    backtrack([], [False] * (n + 1))
    return result
